# SharePoint via Microsoft Graph API
import httpx

def search_sharepoint(query: str, token: str, site_id: str, limit: int = 5) -> list[dict]:
    resp = httpx.post(
        "https://graph.microsoft.com/v1.0/search/query",
        headers={"Authorization": f"Bearer {token}", "Content-Type": "application/json"},
        json={
            "requests": [{
                "entityTypes": ["driveItem"],
                "query": {"queryString": query},
                "from": 0,
                "size": limit,
            }]
        },
        timeout=15,
    )
    resp.raise_for_status()
    hits = resp.json().get("value", [{}])[0].get("hitsContainers", [{}])[0].get("hits", [])
    return [
        {
            "name": h["resource"].get("name"),
            "url": h["resource"].get("webUrl"),
            "summary": h.get("summary", ""),
        }
        for h in hits
    ]

# Confluence via REST API
def search_confluence(query: str, base_url: str, token: str, limit: int = 5) -> list[dict]:
    resp = httpx.get(
        f"{base_url}/rest/api/content/search",
        headers={"Authorization": f"Bearer {token}"},
        params={"cql": f'text ~ "{query}" AND type = "page"', "limit": str(limit)},
        timeout=15,
    )
    resp.raise_for_status()
    results = resp.json().get("results", [])
    return [
        {
            "title": r.get("title"),
            "url": f"{base_url}{r['_links'].get('webui', '')}",
            "space": r.get("space", {}).get("name", ""),
        }
        for r in results
    ]
